diff --git a/App/Layers/W1/BaseApp/Inventory/Tracking/ItemTrackingManagement.Codeunit.al b/App/Layers/W1/BaseApp/Inventory/Tracking/ItemTrackingManagement.Codeunit.al
index 20d4cff0..406dfc3b 100644
--- a/App/Layers/W1/BaseApp/Inventory/Tracking/ItemTrackingManagement.Codeunit.al
+++ b/App/Layers/W1/BaseApp/Inventory/Tracking/ItemTrackingManagement.Codeunit.al
@@ -677,12 +677,52 @@ codeunit 6500 "Item Tracking Management"

         OnCopyHandledItemTrkgToInvLineOnBeforeInsertProspectReservEntry(ToSalesInvLine);

-        InsertProspectReservEntryFromItemEntryRelationAndSourceData(
-          ItemEntryRelation, ToSalesInvLine."Document Type".AsInteger(), ToSalesInvLine."Document No.", ToSalesInvLine."Line No.");
+        CopyHandledItemTrkgToInvLineInternal(
+          ItemEntryRelation, ToSalesInvLine."Document Type".AsInteger(), ToSalesInvLine."Document No.", ToSalesInvLine."Line No.", ToSalesInvLine.Quantity);

         OnAfterCopyHandledItemTrkgToInvLine(FromSalesLine, ToSalesInvLine);
     end;

+    local procedure CopyHandledItemTrkgToInvLineInternal(var ItemEntryRelation: Record "Item Entry Relation"; SourceSubtype: Option; SourceID: Code[20]; SourceRefNo: Integer; LineQuantity: Decimal)
+    var
+        TrackingSpecification: Record "Tracking Specification";
+        QtyBase: Decimal;
+        TotalQtyBase: Decimal;
+        AdjustedQtyBase: Decimal;
+    begin
+        if not ItemEntryRelation.FindSet() then
+            exit;
+
+        // First pass: calculate total quantity from tracking specifications
+        repeat
+            TrackingSpecification.Get(ItemEntryRelation."Item Entry No.");
+            QtyBase := TrackingSpecification."Quantity (Base)" - TrackingSpecification."Quantity Invoiced (Base)";
+            if QtyBase > 0 then
+                TotalQtyBase += QtyBase;
+        until ItemEntryRelation.Next() = 0;
+
+        // Second pass: insert reservation entries with quantities limited to the line quantity (if LineQuantity > 0)
+        if ItemEntryRelation.FindSet() then
+            repeat
+                TrackingSpecification.Get(ItemEntryRelation."Item Entry No.");
+                QtyBase := TrackingSpecification."Quantity (Base)" - TrackingSpecification."Quantity Invoiced (Base)";
+                if QtyBase > 0 then begin
+                    // If LineQuantity is specified and greater than 0, scale the tracked quantity proportionally
+                    if (LineQuantity > 0) and (TotalQtyBase > 0) then
+                        AdjustedQtyBase := Round(QtyBase * LineQuantity / TotalQtyBase, 0.00001)
+                    else
+                        AdjustedQtyBase := QtyBase;
+                    
+                    // Ensure we don't exceed the line quantity in total (if LineQuantity > 0)
+                    if (LineQuantity > 0) and (AdjustedQtyBase > LineQuantity) then
+                        AdjustedQtyBase := LineQuantity;
+                    
+                    InsertReservEntryFromTrackingSpec(
+                      TrackingSpecification, SourceSubtype, SourceID, SourceRefNo, AdjustedQtyBase);
+                end;
+            until ItemEntryRelation.Next() = 0;
+    end;
+
     procedure CopyHandledItemTrkgToInvLine(FromPurchLine: Record "Purchase Line"; ToPurchLine: Record "Purchase Line")
     begin
         CopyHandledItemTrkgToPurchLine(FromPurchLine, ToPurchLine, false);

