+    local procedure AdjustRoundingErrorOnTracking(var ReservEntry: Record "Reservation Entry"; TotalQtyTracked: Decimal)
+    var
+        TrackingReservEntry: Record "Reservation Entry";
+        SupplyReservEntry: Record "Reservation Entry";
+        SumQuantity: Decimal;
+        ExpectedQuantity: Decimal;
+        QuantityRoundingDiff: Decimal;
+        LastEntryNo: Integer;
+        LastPositive: Boolean;
+    begin
+        if TotalQtyTracked = 0 then
+            exit;
+
+        TrackingReservEntry.SetSourceFilter(
+            ReservEntry."Source Type", ReservEntry."Source Subtype", 
+            ReservEntry."Source ID", ReservEntry."Source Ref. No.", false);
+        TrackingReservEntry.SetRange("Reservation Status", TrackingReservEntry."Reservation Status"::Tracking);
+        TrackingReservEntry.SetRange(Positive, ReservEntry.Positive);
+        
+        if not TrackingReservEntry.FindSet() then
+            exit;
+
+        ExpectedQuantity := Round(TotalQtyTracked / ReservEntry."Qty. per Unit of Measure", 0.00001);
+        SumQuantity := 0;
+        LastEntryNo := 0;
+        LastPositive := false;
+
+        repeat
+            SumQuantity += TrackingReservEntry.Quantity;
+            LastEntryNo := TrackingReservEntry."Entry No.";
+            LastPositive := TrackingReservEntry.Positive;
+        until TrackingReservEntry.Next() = 0;
+
+        QuantityRoundingDiff := ExpectedQuantity - SumQuantity;
+        
+        if Abs(QuantityRoundingDiff) > 0.00001 then begin
+            TrackingReservEntry.Get(LastEntryNo, LastPositive);
+            TrackingReservEntry.Quantity := TrackingReservEntry.Quantity + QuantityRoundingDiff;
+            TrackingReservEntry.Modify();
+
+            if (ReservEntry."Reservation Status" = ReservEntry."Reservation Status"::Reservation) or 
+               (ReservEntry."Reservation Status" = ReservEntry."Reservation Status"::Tracking) then
+                if SupplyReservEntry.Get(LastEntryNo, not LastPositive) then begin
+                    SupplyReservEntry.Quantity := SupplyReservEntry.Quantity - QuantityRoundingDiff;
+                    SupplyReservEntry.Modify();
+                end;
+        end;
+    end;
+
